// AI generated by GitHub Copilot Claude Opus 4.7 START
// ThreadedFileHandle: returned to callers of VfsServerInterface::open().
// Multiple ThreadedFileHandles can share the same OpenFile (and thus
// the same underlying drive handle) when open() is called repeatedly
// for the same path. Each ThreadedFileHandle keeps its OWN cursor
// (m_pos) and its own append flag so the openers do not stomp on
// each other's read/write position.
//
// Every operation on the shared underlying handle is performed under
// the OpenFile's mutex; the underlying handle is seek()ed to m_pos
// (or to file_size() for append writes) just before each call so the
// shared handle's internal position stays consistent with what this
// opener expects.
//
// Read paths in the base FS are lock-free; the per-OpenFile mutex
// here serialises CALLS to the FS for a single file but does not
// serialise calls for different files. The base FS's own fine-grained
// locks (m_inode_meta_mutex / m_free_data_pages_mutex / m_mem_mutex)
// keep cross-file operations safe.
class ThreadedFileHandle : public SimpleFlashFs::FileInterface
{
private:
    using OpenFile = SimpleFlashFs::Vfs::SimpleFlashFsVfsServer::OpenFile;

    std::shared_ptr<OpenFile>   m_entry;
    std::size_t                 m_pos    = 0;
    bool                        m_append = false;

    // Convenience: dereferenced underlying handle. Caller must hold
    // m_entry->mutex.
    SimpleFlashFs::FileInterface & uh() const { return *m_entry->handle; }
    bool                            uh_ok() const { return m_entry && m_entry->handle && !!*m_entry->handle; }

public:
    ThreadedFileHandle( std::shared_ptr<OpenFile> entry,
                        std::ios_base::openmode   mode )
    : m_entry ( std::move(entry) ),
      m_pos   ( 0 ),
      m_append( (mode & std::ios::app) != 0 )
    {
        // ios::ate -> start the per-handle cursor at the end of the
        // file as observed RIGHT NOW. Subsequent writes by another
        // opener will be invisible to this cursor until we re-seek.
        if( (mode & std::ios::ate) != 0 ) {
            std::lock_guard l( m_entry->mutex );
            if( uh_ok() ) {
                m_pos = uh().file_size();
            }
        }
    }

    bool operator!() const override {
        return !uh_ok();
    }

    std::size_t write( const std::byte *data, std::size_t size ) override {
        std::lock_guard l( m_entry->mutex );
        if( !uh_ok() ) {
            return 0;
        }
        const std::size_t target = m_append ? uh().file_size() : m_pos;
        if( uh().tellg() != target ) {
            uh().seek( target );
        }
        const std::size_t n = uh().write( data, size );
        m_pos = uh().tellg();
        return n;
    }

    std::size_t read( std::byte *data, std::size_t size ) override {
        std::lock_guard l( m_entry->mutex );
        if( !uh_ok() ) {
            return 0;
        }
        if( uh().tellg() != m_pos ) {
            uh().seek( m_pos );
        }
        const std::size_t n = uh().read( data, size );
        m_pos = uh().tellg();
        return n;
    }

    bool flush() override {
        std::lock_guard l( m_entry->mutex );
        if( !uh_ok() ) {
            return false;
        }
        return uh().flush();
    }

    // Per-handle cursor; no need to touch the shared handle.
    std::size_t tellg() const override {
        return m_pos;
    }

    std::size_t file_size() const override {
        std::lock_guard l( m_entry->mutex );
        if( !uh_ok() ) {
            return 0;
        }
        return uh().file_size();
    }

    bool eof() const override {
        std::lock_guard l( m_entry->mutex );
        if( !uh_ok() ) {
            return true;
        }
        const std::size_t sz = uh().file_size();
        if( sz == 0 ) return true;
        return m_pos >= sz;
    }

    bool seek( std::size_t pos_ ) override {
        // Pure per-handle change; we re-sync the shared handle on
        // the next read/write so two openers can keep independent
        // cursors without thrashing the underlying handle.
        m_pos = pos_;
        return true;
    }

    bool delete_file() override {
        std::lock_guard l( m_entry->mutex );
        if( !uh_ok() ) {
            return false;
        }
        // After this the underlying handle is disconnected
        // (fs == nullptr inside FileHandle). Sibling openers will
        // see operator!() == true and their next read/write/flush
        // will return 0/false instead of crashing.
        return uh().delete_file();
    }

    bool rename_file( const std::string_view & new_file_name ) override {
        std::lock_guard l( m_entry->mutex );
        if( !uh_ok() ) {
            return false;
        }
        return uh().rename_file( new_file_name );
    }

    bool truncate( std::size_t new_size ) override {
        std::lock_guard l( m_entry->mutex );
        if( !uh_ok() ) {
            return false;
        }
        const bool ok = uh().truncate( new_size );
        if( ok && m_pos > new_size ) {
            m_pos = new_size;
        }
        return ok;
    }

    std::string_view get_file_name() const override {
        std::lock_guard l( m_entry->mutex );
        if( !uh_ok() ) {
            return {};
        }
        return uh().get_file_name();
    }

    bool is_append_mode() const override {
        // append is per-handle metadata, no need to lock.
        return m_append;
    }
};
// AI generated by GitHub Copilot Claude Opus 4.7 END

