bool SimpleFlashFsVfsServer::register_drive( std::shared_ptr<VfsDriveInterface> drive )
{
    auto lock = std::scoped_lock(m_mutex);
    m_drives.push_back( drive );
    return true;
}

file_handle_t SimpleFlashFsVfsServer::open( const std::string_view & path, std::ios_base::openmode mode )
{
    std::string_view file_path = path;
    const auto drive_name = parse_drive_name( file_path );

    // CPPDEBUG( Tools::format( "open file: %s at drive: %s", file_path, drive_name ) );

    auto lock = std::scoped_lock(m_mutex);

    // AI generated by GitHub Copilot Claude Opus 4.7 START
    // Build a normalised key so "/a/foo" and "a/foo" map to the same
    // entry. parse_drive_name has already stripped the drive prefix
    // and any leading slash from file_path.
    std::string key;
    key.reserve( drive_name.size() + 1 + file_path.size() );
    key.append( drive_name ).append( ":" ).append( file_path );

    // Step 1: is the file already open by another handle?
    if( auto it = m_open_files.find( key ); it != m_open_files.end() ) {
        if( auto entry = it->second.lock(); entry && entry->handle && !!*entry->handle ) {
            // Yes - reuse the shared OpenFile.
            //
            // If the caller asked for trunc, propagate it now so that
            // BOTH openers see the empty file. This matches
            // POSIX-ish semantics for O_TRUNC on an already-open file.
            if( (mode & std::ios::trunc) != 0 ) {
                std::lock_guard h_lock( entry->mutex );
                if( !!*entry->handle ) {
                    entry->handle->truncate( 0 );
                }
            }
            return std::make_unique<ThreadedFileHandle>( std::move(entry), mode );
        }
        // weak_ptr expired (or handle is disconnected) - drop the
        // stale entry and fall through to fresh open.
        m_open_files.erase( it );
    }

    // Step 2: first opener for this path. Find the drive and open
    // the file the traditional way.
    bool drive_found = false;

    for( auto & drive : m_drives ) {
        if( drive->get_drive_name() != drive_name ) {
            continue;
        }

        drive_found = true;

        if( !drive->initialized() ) {
            if( !drive->init() ) {
                return {};
            }
        }

        auto file = drive->open( file_path, mode );
        if( file ) {
            // Move the unique_ptr<FileInterface> into an OpenFile
            // and store a weak_ptr in the table.
            auto entry = std::make_shared<OpenFile>( std::move(file) );
            m_open_files[ key ] = entry;
            return std::make_unique<ThreadedFileHandle>( std::move(entry), mode );
        }
    }
    // AI generated by GitHub Copilot Claude Opus 4.7 END

    if( !drive_found ) {
        CPPDEBUG( Tools::format( "drive not found: %s", drive_name ) );
    } else {
        CPPDEBUG( Tools::format( "file not found: %s at drive: %s", file_path, drive_name ) );
    }

    return {};
}

std::string_view SimpleFlashFsVfsServer::get_drive_name( const std::string_view & path ) const
{
    std::string_view drive_name = path;

    if( drive_name.starts_with('/') ) {
        drive_name.remove_prefix(1);
    }

    const auto pos = drive_name.find( '/' );

    if( pos != std::string_view::npos ) {
        return drive_name.substr( 0, pos );
    }
    return drive_name;
}

std::string_view SimpleFlashFsVfsServer::parse_drive_name( std::string_view & path ) const
{
    std::string_view            drive_name = path;
    std::string_view::size_type file_name_start_pos = 0;

    if( drive_name.starts_with('/') ) {
        drive_name.remove_prefix(1);
        file_name_start_pos++;
    }

    const auto pos = drive_name.find( '/' );

    if( pos != std::string_view::npos ) {
        path.remove_prefix(pos + file_name_start_pos);

        if( path.starts_with('/') ) {
            path.remove_prefix(1);
        }

        return drive_name.substr( 0, pos );
    }
    return drive_name;
}

std::vector<std::string_view> SimpleFlashFsVfsServer::get_drive_names() const
{
    auto lock = std::scoped_lock(m_mutex);
    std::vector<std::string_view> drive_names;
    for( auto & drive : m_drives ) {
        drive_names.push_back( drive->get_drive_name() );
    }
    return drive_names;
}

bool SimpleFlashFsVfsServer::list_files( list_files_callback_t callback, const std::string_view & drive_name )
{
    auto lock = std::scoped_lock(m_mutex);
    for( auto & drive : m_drives ) {

        if( !drive_name.empty() && drive->get_drive_name() != drive_name ) {
            continue;
        }

        if( !drive->initialized() ) {
            if( !drive->init() ) {
                continue;
            }
        }

        if( !drive->list_files( callback ) ) {
            return false;
        }
    }
    return true;
}

void SimpleFlashFsVfsServer::create( const std::string_view & drive_name )
{
    auto lock = std::scoped_lock(m_mutex);
    for( auto & drive : m_drives ) {
        if( drive->get_drive_name() == drive_name ) {
            drive->create();
            return;
        }
    }
}

std::string SimpleFlashFsVfsServer::get_current_drive() const
{
    auto lock = std::scoped_lock(m_mutex);
    return m_current_drive;
}

bool SimpleFlashFsVfsServer::set_current_drive( const std::string_view & drive_name )
{
    auto lock = std::scoped_lock(m_mutex);
    
    // Check if the drive exists
    for( auto & drive : m_drives ) {
        if( drive->get_drive_name() == drive_name ) {
            m_current_drive = std::string(drive_name);

            if( !drive->initialized() ) {
                if( !drive->init() ) {
                    return false;
                }
            }

            return true;
        }
    }
    
    return false;
}

void SimpleFlashFsVfsServer::cleanup()
{
    auto lock = std::scoped_lock(m_mutex);
    for( auto & drive : m_drives ) {
        drive->cleanup();
    }
    // AI generated by GitHub Copilot Claude Opus 4.7 START
    // Reap any open-file table entries whose last shared_ptr was
    // released since the previous cleanup. Without this the map
    // would slowly grow with stale weak_ptr placeholders.
    purge_expired_open_files();
    // AI generated by GitHub Copilot Claude Opus 4.7 END
}

// AI generated by GitHub Copilot Claude Opus 4.7 START
void SimpleFlashFsVfsServer::purge_expired_open_files()
{
    // Caller must already hold m_mutex.
    for( auto it = m_open_files.begin(); it != m_open_files.end(); ) {
        if( it->second.expired() ) {
            it = m_open_files.erase( it );
        } else {
            ++it;
        }
    }
}
